package jetbrains.mps.baselanguage.unitTest.execution.launcher;

/*Generated by MPS */

import jetbrains.mps.logging.Logger;
import java.util.List;
import org.junit.platform.engine.DiscoverySelector;
import java.util.LinkedList;
import org.junit.platform.engine.discovery.DiscoverySelectors;

/**
 * No-platform alternative to supply JUnit5 tests, much like {@code JUnit5ScriptTestContributor}, just no MPS modules and classloading
 */
/*package*/ class JUnit5TestContributorConverter implements JUnit5TestContributor {
  private static final Logger LOG = Logger.getLogger(JUnit5TestContributorConverter.class);
  private final TestsContributor myTestsContributor;

  public JUnit5TestContributorConverter(TestsContributor toConvert) {
    myTestsContributor = toConvert;
  }

  @Override
  public List<DiscoverySelector> collectSelectors() throws Exception {
    List<DiscoverySelector> selectors = new LinkedList<DiscoverySelector>();
    for (ExecutorScript.TestRecord tr : myTestsContributor.tests()) {
      final ClassLoader classLoader = myTestsContributor.classLoader(tr);
      for (int i = 0, x = tr.myTestQualifiedName.size(); i < x; i++) {
        String qualifiedName = tr.myTestQualifiedName.get(i);
        boolean isTestCase = Boolean.valueOf(tr.isTestCase.get(i)).booleanValue();
        DiscoverySelector r = (isTestCase ? processTestClass(classLoader, qualifiedName) : processTestMethod(classLoader, qualifiedName));
        if (r != null) {
          selectors.add(r);
        }
      }
    }
    return selectors;
  }

  private DiscoverySelector processTestClass(ClassLoader cl, String classString) {
    Class<?> testClass = getTestClass(cl, classString);
    return (testClass != null ? DiscoverySelectors.selectClass(testClass) : null);
  }

  private DiscoverySelector processTestMethod(ClassLoader cl, String methodString) {
    int index = methodString.lastIndexOf('.');
    String testClassName = methodString.substring(0, index);
    String testMethod = methodString.substring(index + 1);
    Class<?> testClass = getTestClass(cl, testClassName);
    return (testClass != null ? DiscoverySelectors.selectMethod(testClass, testMethod) : null);
  }


  private static Class<?> getTestClass(ClassLoader cl, String className) {
    Class<?> testClass = null;
    try {
      testClass = cl.loadClass(className);
    } catch (ClassNotFoundException e) {
      if (LOG.isErrorLevel()) {
        LOG.error("Test class " + className + " has not been found: it will be skipped", e);
      }
    }
    return testClass;
  }
}
